$\begin{align}
\dfrac{4r}{5r + 6} &= \dfrac{1}{6}
\\\\
(5r+6)\cdot \dfrac{4r}{5r + 6} &= (5r+6)\cdot \dfrac{1}{6}
\\\\
4r&=\dfrac56 r+1
\\\\
\dfrac{19}{6}r&=1
\\\\
r&=\dfrac{6}{19}
\end{align}$

$\begin{align}
\dfrac{5x - 5}{x - 2} &= \dfrac{1}{3}
\\\\
(x-2)\cdot \dfrac{5x - 5}{x - 2} &= (x-2)\cdot \dfrac{1}{3}
\\\\
5x-5&=\dfrac13 x-\dfrac23
\\\\
\dfrac{14}{3}x&=\dfrac{13}{3}
\\\\
x&=\dfrac{13}{14}
\end{align}$

$\begin{align}
\dfrac{2y - 4}{y + 7} &= \dfrac{1}{3}
\\\\
(y+7)\cdot \dfrac{2y - 4}{y + 7} &= (y+7)\cdot \dfrac{1}{3}
\\\\
2y-4&=\dfrac13 y+\dfrac73
\\\\
\dfrac53 y&=\dfrac{19}{3}
\\\\
y&=\dfrac{19}{5}
\end{align}$
